import numpy as np

def matrix_dot_vector(a: list[list[int|float]], b: list[int|float]) -> list[int|float]:
    mat = np.array(a)
    vec = np.array(b)
    if mat.shape[1] != vec.shape[0]:
        return -1
    return np.dot(mat, vec).tolist()
